{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires transitioning from a canonical ensemble (isothermal) to a microcanonical ensemble (adiabatic) for a polymer chain. This involves determining the change in the effective degrees of freedom and the resulting scaling of the force law.",
  "helpers": [
    {
      "label": "thermodynamic_regime_specialist",
      "instructions": "Determine the relationship between the isothermal force F_iso(x) and the adiabatic force F_adi(x) for a system of n particles. Specifically, derive how the internal energy constraint in a thermally isolated (microcanonical) system modifies the partition function or the entropy-based force derivation compared to the standard isothermal case, accounting for the change in the effective number of degrees of freedom available to the chain."
    },
    {
      "label": "statistical_mechanics_specialist",
      "instructions": "Starting from the isothermal force law for a freely jointed chain, which follows F_iso(x) proportional to x / (n*l^2 - x^2), apply the adiabatic constraint derived by the thermodynamic specialist to find the exact functional form of F(x). Focus on identifying the correct power-law scaling and the specific coefficient that accounts for the adiabatic temperature change as the chain is stretched."
    }
  ],
  "synthesis_brief": "Combine the thermodynamic scaling factor (the relationship between isothermal and adiabatic ensembles for this specific degree-of-freedom count) with the base isothermal force law of the freely jointed chain to produce the final exact expression for F(x)."
}

